INSERT IGNORE INTO bluenote_rank.rank_score_change_log (
    change_id, source_event_id, source_event_type, rank_code, period_id,
    member_type, member_id, source_type, source_id, field_name,
    delta_value, score_delta, score_after, occurred_at, created_at
) VALUES (
    #{changeId}, #{sourceEventId}, #{sourceEventType}, #{rankCode}, #{periodId},
    #{memberType}, #{memberId}, #{sourceType}, #{sourceId}, #{fieldName},
    #{deltaValue}, #{scoreDelta}, #{scoreAfter}, #{occurredAt}, #{createdAt}
)
